HTML_CONTENT = '<!DOCTYPE html>\n<html lang="en">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>YT Scraper API UI</title>\n    <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;600;800&display=swap" rel="stylesheet">\n    <style>\n        :root {\n            --bg-color: #0f172a;\n            --surface-color: #1e293b;\n            --primary-color: #3b82f6;\n            --primary-hover: #2563eb;\n            --text-primary: #f8fafc;\n            --text-secondary: #94a3b8;\n            --accent-color: #10b981;\n            --danger-color: #ef4444;\n            --border-radius: 12px;\n        }\n\n        * {\n            box-sizing: border-box;\n            margin: 0;\n            padding: 0;\n        }\n\n        body {\n            font-family: \'Inter\', sans-serif;\n            background-color: var(--bg-color);\n            color: var(--text-primary);\n            line-height: 1.6;\n            min-height: 100vh;\n            display: flex;\n            flex-direction: column;\n            align-items: center;\n            padding: 2rem;\n        }\n\n        .container {\n            width: 100%;\n            max-width: 800px;\n            background-color: var(--surface-color);\n            padding: 2rem;\n            border-radius: var(--border-radius);\n            box-shadow: 0 10px 25px rgba(0,0,0,0.5);\n            animation: fadeIn 0.5s ease;\n        }\n\n        h1 {\n            text-align: center;\n            margin-bottom: 0.5rem;\n            font-weight: 800;\n            background: linear-gradient(90deg, #3b82f6, #8b5cf6);\n            -webkit-background-clip: text;\n            -webkit-text-fill-color: transparent;\n        }\n\n        p.subtitle {\n            text-align: center;\n            color: var(--text-secondary);\n            margin-bottom: 2rem;\n        }\n\n        .input-group {\n            display: flex;\n            gap: 10px;\n            margin-bottom: 2rem;\n        }\n\n        input[type="text"] {\n            flex: 1;\n            padding: 1rem;\n            border-radius: var(--border-radius);\n            border: 1px solid #334155;\n            background-color: #0f172a;\n            color: var(--text-primary);\n            font-size: 1rem;\n            outline: none;\n            transition: all 0.3s ease;\n        }\n\n        input[type="text"]:focus {\n            border-color: var(--primary-color);\n            box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.3);\n        }\n\n        button {\n            padding: 1rem 2rem;\n            border: none;\n            border-radius: var(--border-radius);\n            background-color: var(--primary-color);\n            color: white;\n            font-weight: 600;\n            font-size: 1rem;\n            cursor: pointer;\n            transition: all 0.3s ease;\n        }\n\n        button:hover {\n            background-color: var(--primary-hover);\n        }\n\n        button:disabled {\n            background-color: #475569;\n            cursor: not-allowed;\n        }\n\n        .loader {\n            display: none;\n            text-align: center;\n            margin: 2rem 0;\n            color: var(--text-secondary);\n        }\n\n        /* Spinner */\n        .spinner {\n            border: 4px solid rgba(255, 255, 255, 0.1);\n            width: 40px;\n            height: 40px;\n            border-radius: 50%;\n            border-left-color: var(--primary-color);\n            animation: spin 1s linear infinite;\n            margin: 0 auto 10px auto;\n        }\n\n        @keyframes spin {\n            0% { transform: rotate(0deg); }\n            100% { transform: rotate(360deg); }\n        }\n\n        @keyframes fadeIn {\n            from { opacity: 0; transform: translateY(20px); }\n            to { opacity: 1; transform: translateY(0); }\n        }\n\n        .result-container {\n            display: none;\n            margin-top: 2rem;\n        }\n\n        .video-meta {\n            display: flex;\n            gap: 1.5rem;\n            background-color: #0f172a;\n            padding: 1rem;\n            border-radius: var(--border-radius);\n            margin-bottom: 2rem;\n            align-items: center;\n        }\n\n        .video-meta img {\n            width: 120px;\n            border-radius: 8px;\n        }\n\n        .meta-info h3 {\n            margin-bottom: 0.5rem;\n        }\n        .meta-info p {\n            color: var(--text-secondary);\n            font-size: 0.9rem;\n        }\n\n        .links-section {\n            margin-bottom: 2rem;\n        }\n\n        .links-section h2 {\n            border-bottom: 1px solid #334155;\n            padding-bottom: 0.5rem;\n            margin-bottom: 1rem;\n            font-size: 1.25rem;\n        }\n\n        .badge-grid {\n            display: grid;\n            grid-template-columns: repeat(auto-fill, minmax(150px, 1fr));\n            gap: 1rem;\n        }\n\n        .link-card {\n            background-color: #0f172a;\n            border: 1px solid #334155;\n            padding: 1rem;\n            border-radius: 8px;\n            text-align: center;\n            transition: all 0.2s ease;\n            text-decoration: none;\n            color: var(--text-primary);\n            display: flex;\n            flex-direction: column;\n            gap: 0.5rem;\n        }\n\n        .link-card:hover {\n            border-color: var(--primary-color);\n            transform: translateY(-2px);\n            background-color: #1e293b;\n        }\n\n        .quality {\n            font-weight: 800;\n            font-size: 1.1rem;\n        }\n        \n        .type {\n            font-size: 0.8rem;\n            color: var(--text-secondary);\n        }\n\n        .size {\n            font-size: 0.8rem;\n            color: var(--accent-color);\n        }\n\n        .audio-only-card {\n            background: linear-gradient(135deg, rgba(16, 185, 129, 0.1), rgba(16, 185, 129, 0.05));\n            border-color: rgba(16, 185, 129, 0.3);\n        }\n\n        .audio-only-card:hover {\n            border-color: var(--accent-color);\n        }\n\n        .error-msg {\n            display: none;\n            color: var(--danger-color);\n            background-color: rgba(239, 68, 68, 0.1);\n            padding: 1rem;\n            border-radius: var(--border-radius);\n            margin-top: 1rem;\n            text-align: center;\n        }\n    </style>\n</head>\n<body>\n\n    <div class="container">\n        <h1>YT Scraper API</h1>\n        <p class="subtitle">Extract Direct Video & MP4 Audio Links Faster</p>\n\n        <div class="input-group">\n            <input type="text" id="videoInput" placeholder="Enter YouTube URL or Video ID (e.g., dQw4w9WgXcQ)">\n            <button id="extractBtn">Extract Links</button>\n        </div>\n\n        <div id="errorMsg" class="error-msg"></div>\n\n        <div id="loader" class="loader">\n            <div class="spinner"></div>\n            <p>Bypassing protections & extracting streams...</p>\n        </div>\n\n        <div id="resultContainer" class="result-container">\n            <div class="video-meta" id="videoMeta">\n                <!-- Meta injected here -->\n            </div>\n\n            <div class="links-section">\n                <h2>🎧 Audio Only (MP4 / M4A)</h2>\n                <div class="badge-grid" id="audioGrid">\n                    <!-- Audio links here -->\n                </div>\n            </div>\n\n            <div class="links-section">\n                <h2>🎬 Video Streams</h2>\n                <div class="badge-grid" id="videoGrid">\n                    <!-- Video links here -->\n                </div>\n            </div>\n        </div>\n    </div>\n\n    <script>\n        function extractVideoId(url) {\n            const regExp = /^.*(youtu.be\\/|v\\/|u\\/\\w\\/|embed\\/|watch\\?v=|\\&v=)([^#\\&\\?]*).*/;\n            const match = url.match(regExp);\n            if (match && match[2].length === 11) {\n                return match[2];\n            }\n            if (url.length === 11) {\n                return url; // Assuming it\'s already an ID\n            }\n            return null;\n        }\n\n        function formatBytes(bytes) {\n            if (!bytes) return \'Unknown Size\';\n            const k = 1024;\n            const sizes = [\'B\', \'KB\', \'MB\', \'GB\'];\n            const i = Math.floor(Math.log(bytes) / Math.log(k));\n            return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + \' \' + sizes[i];\n        }\n\n        function formatDuration(seconds) {\n            const h = Math.floor(seconds / 3600);\n            const m = Math.floor((seconds % 3600) / 60);\n            const s = Math.floor(seconds % 60);\n            return `${h > 0 ? h + \':\' : \'\'}${m < 10 && h > 0 ? \'0\' : \'\'}${m}:${s < 10 ? \'0\' : \'\'}${s}`;\n        }\n\n        document.getElementById(\'extractBtn\').addEventListener(\'click\', async () => {\n            const inputVal = document.getElementById(\'videoInput\').value.trim();\n            const videoId = extractVideoId(inputVal);\n            \n            const btn = document.getElementById(\'extractBtn\');\n            const loader = document.getElementById(\'loader\');\n            const resultContainer = document.getElementById(\'resultContainer\');\n            const errorMsg = document.getElementById(\'errorMsg\');\n            \n            if (!videoId) {\n                errorMsg.textContent = \'Invalid YouTube URL or ID\';\n                errorMsg.style.display = \'block\';\n                return;\n            }\n\n            // Reset UI\n            errorMsg.style.display = \'none\';\n            resultContainer.style.display = \'none\';\n            btn.disabled = true;\n            loader.style.display = \'block\';\n\n            try {\n                // Fetch from our API endpoint\n                const response = await fetch(`/extract/${videoId}`);\n                const res = await response.json();\n\n                if (!response.ok || !res.success) {\n                    throw new Error(res.detail || \'Failed to extract video\');\n                }\n\n                const data = res.data;\n\n                // Set Meta\n                document.getElementById(\'videoMeta\').innerHTML = `\n                    <img src="${data.thumbnail}" alt="Thumbnail">\n                    <div class="meta-info">\n                        <h3>${data.title}</h3>\n                        <p>Duration: ${formatDuration(data.duration)}</p>\n                    </div>\n                `;\n\n                // Set Audio Links (Filter for m4a/mp4)\n                const audioGrid = document.getElementById(\'audioGrid\');\n                audioGrid.innerHTML = \'\';\n                \n                // Sort highest bitrate first\n                const audios = data.audio_streams || [];\n                \n                if (audios.length > 0) {\n                    audios.forEach((audio, idx) => {\n                        const isMp4 = audio.mimeType.includes(\'mp4\') || audio.mimeType.includes(\'m4a\');\n                        \n                        audioGrid.innerHTML += `\n                            <a href="${audio.url}" target="_blank" class="link-card ${isMp4 ? \'audio-only-card\' : \'\'}">\n                                <div class="quality">${audio.bitrate}</div>\n                                <div class="type">${isMp4 ? \'MP4 Audio\' : audio.mimeType.split(\'/\')[1].toUpperCase()}</div>\n                                <div class="size">${formatBytes(audio.size)}</div>\n                            </a>\n                        `;\n                    });\n                } else {\n                    audioGrid.innerHTML = \'<p style="color:var(--text-secondary)">No separate audio streams found.</p>\';\n                }\n\n                // Set Video Links\n                const videoGrid = document.getElementById(\'videoGrid\');\n                videoGrid.innerHTML = \'\';\n                const videos = data.video_streams || [];\n\n                if (videos.length > 0) {\n                    videos.forEach((video) => {\n                        videoGrid.innerHTML += `\n                            <a href="${video.url}" target="_blank" class="link-card">\n                                <div class="quality">${video.quality}</div>\n                                <div class="type">${video.mimeType.split(\'/\')[1].toUpperCase()} • ${video.type === \'progressive\' ? \'Video+Audio\' : \'Video Only\'}</div>\n                                <div class="size">${formatBytes(video.size)}</div>\n                            </a>\n                        `;\n                    });\n                } else {\n                    videoGrid.innerHTML = \'<p style="color:var(--text-secondary)">No video streams found.</p>\';\n                }\n\n                // Show Results\n                resultContainer.style.display = \'block\';\n            } catch (err) {\n                errorMsg.textContent = err.message || \'An error occurred during extraction.\';\n                errorMsg.style.display = \'block\';\n            } finally {\n                btn.disabled = false;\n                loader.style.display = \'none\';\n            }\n        });\n        \n        // Handle Enter key\n        document.getElementById(\'videoInput\').addEventListener(\'keypress\', function(e) {\n            if (e.key === \'Enter\') {\n                document.getElementById(\'extractBtn\').click();\n            }\n        });\n    </script>\n</body>\n</html>\n'